func solve(s string, k int64) string {
	var res []rune
	for _, c := range s {
		if 'a' <= c && c <= 'z' {
			res = append(res, c)
		} else if c == '*' {
			if len(res) > 0 {
				res = res[:len(res)-1]
			}
		} else if c == '#' {
			res = append(res, res...)
		} else if c == '%' {
			for i, j := 0, len(res)-1; i < j; i, j = i+1, j-1 {
				res[i], res[j] = res[j], res[i]
			}
		}
	}
	if k < 0 || k >= int64(len(res)) {
		return "."
	}
	return string(res[k])
}
